    private static string FromGeoJsonRing(string ringJson)
    {
        var points = JsonSerializer.Deserialize<double[][]>(ringJson) ?? [];
        return JsonSerializer.Serialize(points.Select(point => new
        {
            latitude = point[1],
            longitude = point[0]
        }));
    }
